#include<bits/stdc++.h>
using namespace std;
int n,a[200010],ans1,ans2;
int l[200010][2],r[200010][2],s[200010];
int lowbit(int x)
{
    return x&-x;
}
void add(int x,int v)
{
    for(int i=x;i<=n+1;i+=lowbit(i))
    {
        s[i]+=v;
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=s[i];
    }
    return ans;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    for(int i=1;i<=n;i++)
    {
        l[i][0]=query(a[i]);
        add(a[i]+1,1);
        l[i][1]=i-1-l[i][0];
    }
    memset(s,0,sizeof(s));
    for(int i=n;i>=1;i--)
    {
        r[i][0]=query(a[i]);
        add(a[i]+1,1);
        r[i][1]=(n-i)-r[i][0];
    }
    long long ans1=0,ans2=0;
    for(int i=1;i<=n;i++)
    {
        ans1+=1ll*l[i][0]*r[i][0];
        ans2+=1ll*l[i][1]*r[i][1];
    }
    printf("%lld %lld",ans2,ans1);
    return 0;
}
